
/**
 * This object stores animation types available to all scripting handlers through the "AnimationType" keyword.
 */
declare namespace AnimationType {
	var NONE: number;
	var SITTING: number;
	var LYING: number;
	var SNEAKING: number;
	var DANCING: number;
	var AIMING: number;
	var CRAWLING: number;
	var HUGGING: number;
}

